echo 'ZXhwb3J0IHsgQXVyZXhDbGllbnQsIEF1cmV4QXBpRXJyb3IgfSBmcm9tICIuL2NsaWVudC5qcyI7CmV4cG9ydCB7IENhcmRNYW5hZ2VyLCBGRUVTIH0gZnJvbSAiLi9jYXJkLW1hbmFnZXIuanMiOwo=' | base64 --decode > 'src/aurex/index.js'
echo '  done: src/aurex/index.js'
